document.addEventListener("DOMContentLoaded",()=>{const t=document.getElementById("chat-widget-button");const e=document.getElementById("chat-widget-container");const n=document.getElementById("close-chat");const s=document.getElementById("chat-input");const o=document.getElementById("chat-send");const c=document.getElementById("chat-messages");if(!t||!e)return;t.addEventListener("click",()=>{e.classList.toggle("hidden")});n.addEventListener("click",()=>{e.classList.add("hidden")});o.addEventListener("click",d);s.addEventListener("keypress",t=>{if(t.key==="Enter")d()});async function d(){const t=s.value.trim();if(!t)return;a(t,"user");s.value="";const e=a("...","bot");try{const n=await fetch("chat_endpoint.php",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({contents:[{parts:[{text:"You are a helpful space exploration guide for this website. Respond to the user: "+t}]}]})});const o=await n.json();e.remove();if(o.candidates&&o.candidates[0].content.parts[0].text){a(o.candidates[0].content.parts[0].text,"bot")}else{a("I'm sorry, I couldn't process that request.","bot")}}catch(t){console.error("Chat Error:",t);e.remove();a("Error connecting to Gemini API.","bot")}}function a(t,e){const n=document.createElement("div");n.classList.add("chat-message",`${e}-message`);if(e==="bot"){n.innerHTML=marked.parse(t)}else{n.textContent=t}c.appendChild(n);c.scrollTop=c.scrollHeight;return n}});